mapper.update:
BEGIN
update DP_TABLE_ORGANIZATION_ASSETS set update_date = #{item.updateDate,jdbcType=VARCHAR}, update_period = #{item.updatePeriod,jdbcType=VARCHAR}, DATARESOURCE_CODE = #{item.belongSystemCode,jdbcType=VARCHAR}, LASTDATAMODIFIEDTIME = #{item.lastDataModifiedTime,jdbcType=VARCHAR} where upper(TABLE_NAME_EN) = upper(#{item.tableName,jdbcType=VARCHAR}) and upper(TABLE_TYPE) = upper(#{item.organization,jdbcType=VARCHAR}) and upper(TABLE_PROJECT) = upper(#{item.projectName,jdbcType=VARCHAR}) and STATISTICS_TIME >= date(NOW()) ;
END;

mapper.delete:
delete from synlte.syndmg_table_all
where tablename=#{sydmgParam.TABLENAME,jdbcType=VARCHAR}
  and tableproject=#{sydmgParam.TABLEPROJECT,jdbcType=VARCHAR}
  and tabletype=#{sydmgParam.TABLETYPE,jdbcType=VARCHAR}
  and partitionDate < #{minDelDate,jdbcType=INTEGER}
